package com.google.gson;
import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.JsonElement;
import com.google.gson.JsonNull;
import org.junit.jupiter.api.Test;

class JsonElementTest {

  @Test
  void getAsJsonNull_whenIsJsonNullTrue_returnsThisAsJsonNull() {
    JsonElement jsonElement = mock(JsonElement.class);
    when(jsonElement.isJsonNull()).thenReturn(true);
    when(jsonElement.toString()).thenReturn("JsonNull");

    // Cast to JsonNull must be possible, so mock must extend JsonNull or we create a subclass:
    JsonNull jsonNull = new JsonNull() {
      @Override
      public JsonElement deepCopy() {
        return this;
      }
    };

    JsonElement spyJsonElement = spy(jsonNull);
    when(spyJsonElement.isJsonNull()).thenReturn(true);

    JsonNull result = spyJsonElement.getAsJsonNull();

    assertSame(spyJsonElement, result);
  }

  @Test
  void getAsJsonNull_whenIsJsonNullFalse_throwsIllegalStateException() {
    JsonElement jsonElement = mock(JsonElement.class);
    when(jsonElement.isJsonNull()).thenReturn(false);
    when(jsonElement.toString()).thenReturn("NotJsonNull");

    IllegalStateException exception = assertThrows(IllegalStateException.class, jsonElement::getAsJsonNull);
    assertEquals("Not a JSON Null: NotJsonNull", exception.getMessage());
  }
}
